export function validateSkillId(skillId, existingIds = []) {
  const raw = String(skillId || "");
  if (raw.length < 3) return { valid: false, error: "技能标识至少 3 个字符" };
  if (raw.length > 64) return { valid: false, error: "技能标识不能超过 64 个字符" };
  if (!/^[a-z0-9_-]+$/.test(raw)) return { valid: false, error: "仅允许小写字母、数字、下划线和连字符" };
  if (existingIds.includes(raw)) return { valid: false, error: "技能标识已存在" };
  return { valid: true, error: "" };
}

export function validatePublishReady(skill) {
  const content = String(skill.content || "");
  const required = ["/when_to_use", "/input", "/output", "/constraints"];
  const missing = required.filter(section => !content.includes(section));
  return { ready: missing.length === 0, missing };
}

export function validateImportFile(filename, size) {
  const name = String(filename || "");
  const allowedExts = [".md", ".json", ".yaml", ".yml", ".zip"];
  const ext = name.slice(name.lastIndexOf(".")).toLowerCase();
  if (!ext || !allowedExts.includes(ext)) {
    return { valid: false, error: "仅支持 .md、.json、.yaml、.yml、.zip 格式" };
  }
  const maxSize = 10 * 1024 * 1024; // 10MB
  if (size > maxSize) {
    return { valid: false, error: "文件大小不能超过 10MB" };
  }
  const dangerousExts = [".exe", ".sh", ".bat", ".cmd", ".ps1", ".vbs", ".jar", ".py", ".rb"];
  if (dangerousExts.includes(ext)) {
    return { valid: false, error: "不允许上传可执行脚本或程序文件" };
  }
  return { valid: true, error: "" };
}

export function scanSkill(skill) {
  const content = `${skill.content || ""} ${skill.description || ""}`;
  const findings = [];

  const check = (label, patterns, hitLabel, description, fix) => {
    for (const pattern of patterns) {
      const match = content.match(pattern);
      if (match) {
        const snippet = (match[0] || "").slice(0, 50);
        findings.push({
          dimension: label,
          level: hitLabel,
          location: skill.assets?.find(a => a.endsWith(".md") || a.endsWith(".json") || a.endsWith(".yaml")) || "SKILL.md",
          detail: description,
          match: snippet,
          suggestion: fix
        });
      }
    }
  };

  check("敏感凭证", [/api\s*key/i, /token/i, /密码/, /私钥/, /secret/i, /access_key/i], "高", "检测到疑似敏感凭证", "使用平台变量或安全引用替换明文凭证，参考安全配置文档");
  check("提示词注入", [/忽略.*指令/, /忽略.*规则/, /override.*instruction/i, /ignore.*prompt/i, /system.*message/i], "高", "检测到可能的提示词注入风险", "移除覆盖系统指令的语句，采用白名单机制限制输入范围");
  check("危险操作", [/删除文件/, /subprocess/i, /os\.system/i, /exec/i, /eval/i, /fs\.unlink/i, /rm\s+-rf/i], "高", "检测到危险操作指令", "移除直接调用系统命令或文件删除的指令，改用平台提供的安全 API");
  check("网络风险", [/外网发送/, /169\.254/, /curl/i, /fetch.*http/i, /request.*http/i, /axios/i], "中", "检测到外部网络请求", "声明网络访问需求并限制目标域名，或使用平台网络代理");
  check("数据泄露", [/日志.*输出/, /console\.log/, /print\s*\(/, /write.*file/i, /上传/, /导出.*数据/], "中", "检测到可能的数据泄露操作", "限制数据输出范围，避免将用户数据写入外部存储");
  check("依赖风险", [/require\(/, /import\s+/, /from\s+['"]/, /npm install/i, /pip install/i], "低", "检测到外部依赖引用", "声明外部依赖并提供校验和来源，使用平台依赖管理");
  check("结构冲突", [/\/input[\s\S]*\/input/, /\/output[\s\S]*\/output/, /\/constraints[\s\S]*\/constraints/], "中", "检测到声明块重复定义", "移除重复声明块，合并内容到唯一块中");
  check("生成质量风险", [/大约/, /大概/, /maybe/i, /perhaps/i, /可能/, /应该/, /不确定/], "低", "检测到模糊表述可能影响生成质量", "使用精确表述替换模糊词语，定义明确的行为边界");

  if (findings.length) {
    const highCount = findings.filter(f => f.level === "高").length;
    const midCount = findings.filter(f => f.level === "中").length;
    const lowCount = findings.filter(f => f.level === "低").length;
    const level = highCount > 0 ? "高" : midCount > 0 ? "中" : "低";
    return {
      summary: { status: "扫描失败", level, passed: false },
      scan: {
        level,
        issues: findings.length,
        highCount,
        midCount,
        lowCount,
        result: "不通过",
        time: new Date().toLocaleString("zh-CN", { hour12: false })
      },
      findings
    };
  }
  return {
    summary: { status: "已发布", level: "低", passed: true },
    scan: {
      level: "低",
      issues: 0,
      highCount: 0,
      midCount: 0,
      lowCount: 0,
      result: "通过",
      time: new Date().toLocaleString("zh-CN", { hour12: false })
    },
    findings: [{ dimension: "全部检查项", level: "低", location: "-", detail: "结构化声明块完整，未发现高风险内容", match: "", suggestion: "" }]
  };
}

