245	export function scanSkill(skill) {
246	  const content = `${skill.content || ""} ${skill.description || ""}`;
247	  const findings = [];
248	
249	  const check = (label, patterns, hitLabel, description, fix) => {
250	    for (const pattern of patterns) {
251	      const match = content.match(pattern);
252	      if (match) {
253	        const snippet = (match[0] || "").slice(0, 50);
254	        findings.push({
255	          dimension: label,
256	          level: hitLabel,
257	          location: skill.assets?.find(a => a.endsWith(".md") || a.endsWith(".json") || a.endsWith(".yaml")) || "SKILL.md",
258	          detail: description,
259	          match: snippet,
260	          suggestion: fix
261	        });
262	      }
263	    }
264	  };
265	
266	  check("敏感凭证", [/api\s*key/i, /token/i, /密码/, /私钥/, /secret/i, /access_key/i], "高", "检测到疑似敏感凭证", "使用平台变量或安全引用替换明文凭证，参考安全配置文档");
267	  check("提示词注入", [/忽略.*指令/, /忽略.*规则/, /override.*instruction/i, /ignore.*prompt/i, /system.*message/i], "高", "检测到可能的提示词注入风险", "移除覆盖系统指令的语句，采用白名单机制限制输入范围");
268	  check("危险操作", [/删除文件/, /subprocess/i, /os\.system/i, /exec/i, /eval/i, /fs\.unlink/i, /rm\s+-rf/i], "高", "检测到危险操作指令", "移除直接调用系统命令或文件删除的指令，改用平台提供的安全 API");
269	  check("网络风险", [/外网发送/, /169\.254/, /curl/i, /fetch.*http/i, /request.*http/i, /axios/i], "中", "检测到外部网络请求", "声明网络访问需求并限制目标域名，或使用平台网络代理");
270	  check("数据泄露", [/日志.*输出/, /console\.log/, /print\s*\(/, /write.*file/i, /上传/, /导出.*数据/], "中", "检测到可能的数据泄露操作", "限制数据输出范围，避免将用户数据写入外部存储");
271	  check("依赖风险", [/require\(/, /import\s+/, /from\s+['"]/, /npm install/i, /pip install/i], "低", "检测到外部依赖引用", "声明外部依赖并提供校验和来源，使用平台依赖管理");
272	  check("结构冲突", [/\/input[\s\S]*\/input/, /\/output[\s\S]*\/output/, /\/constraints[\s\S]*\/constraints/], "中", "检测到声明块重复定义", "移除重复声明块，合并内容到唯一块中");
273	  check("生成质量风险", [/大约/, /大概/, /maybe/i, /perhaps/i, /可能/, /应该/, /不确定/], "低", "检测到模糊表述可能影响生成质量", "使用精确表述替换模糊词语，定义明确的行为边界");
274	
275	  if (findings.length) {
276	    const highCount = findings.filter(f => f.level === "高").length;
277	    const midCount = findings.filter(f => f.level === "中").length;
278	    const lowCount = findings.filter(f => f.level === "低").length;
279	    const level = highCount > 0 ? "高" : midCount > 0 ? "中" : "低";
280	    return {
281	      summary: { status: "扫描失败", level, passed: false },
282	      scan: {
283	        level,
284	        issues: findings.length,
285	        highCount,
286	        midCount,
287	        lowCount,
288	        result: "不通过",
289	        time: new Date().toLocaleString("zh-CN", { hour12: false })
290	      },
291	      findings
292	    };
293	  }
294	  return {
295	    summary: { status: "已发布", level: "低", passed: true },
296	    scan: {
297	      level: "低",
298	      issues: 0,
299	      highCount: 0,
300	      midCount: 0,
301	      lowCount: 0,
302	      result: "通过",
303	      time: new Date().toLocaleString("zh-CN", { hour12: false })
304	    },
305	    findings: [{ dimension: "全部检查项", level: "低", location: "-", detail: "结构化声明块完整，未发现高风险内容", match: "", suggestion: "" }]
306	  };
307	}
