309	export function getNextStatus(status, action) {
310	  const transitions = {
311	    "草稿:request_publish": "扫描中",
312	    "扫描失败:request_publish": "扫描中",
313	    "已下架:request_publish": "扫描中",
314	    "扫描中:scan_pass": "已发布",
315	    "扫描中:scan_fail": "扫描失败",
316	    "已发布:unpublish": "已下架"
317	  };
318	  const next = transitions[`${status}:${action}`];
319	  if (!next) throw new Error(`状态 ${status} 不允许执行 ${action}`);
320	  return next;
321	}
322	
323	export function filterSkills(skills, filters = {}) {
324	  const keyword = String(filters.keyword || "").trim().toLowerCase();
325	  return skills.filter(skill => {
326	    const inLibrary = filters.library === "official" ? skill.owner === "official" : skill.owner === "space";
327	    const matchesKeyword = !keyword || [skill.name, skill.skillId, skill.description, skill.category, ...(skill.tags || [])]
328	      .join(" ")
329	      .toLowerCase()
330	      .includes(keyword);
331	    const matchesStatus = !filters.status || filters.status === "全部" || skill.status === filters.status;
332	    const matchesSource = !filters.source || filters.source === "全部" || skill.source === filters.source;
333	    return inLibrary && matchesKeyword && matchesStatus && matchesSource;
334	  });
335	}
