  min-height: 16px;
}

.upload-error {
  color: var(--red);
  font-size: 13px;
  margin-top: 8px;
  padding: 8px 10px;
  border-radius: var(--radius-sm);
  background: #fff1f2;
  border: 1px solid #fecaca;
}

.priority-list {
  display: grid;
  gap: 6px;
  padding: 8px 10px;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  background: #f8fafc;
}

.priority-item {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: #344054;
}

.priority-item b {
  display: inline-block;
  min-width: 24px;
  padding: 1px 5px;
  border-radius: 4px;
  background: var(--blue-soft);
  color: var(--blue);
  font-size: 11px;
  text-align: center;
}

.finding-item {
  margin-top: 12px;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  overflow: hidden;
}

.finding-head {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  background: #f8fafc;
  border-bottom: 1px solid var(--line);
}

.finding-dimension {
  font-weight: 650;
  font-size: 14px;
}

.finding-level {
  display: inline-block;
  padding: 1px 7px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 600;
}

.finding-level.高 {
  color: var(--red);
  background: #fff1f2;
}

.finding-level.中 {
  color: var(--orange);
  background: #fff7ed;
}

.finding-level.低 {
  color: var(--green);
  background: #ecfdf5;
}

.finding-detail {
  display: grid;
  gap: 6px;
  padding: 12px 14px;
  font-size: 13px;
  color: #344054;
}

.finding-detail code {
  font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  font-size: 12px;
  padding: 1px 5px;
  border-radius: 3px;
  background: #f1f3f5;
  color: #c43e52;
}

